import java.io.File
import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.nio.file.{Paths, Path}

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  private val baseDirectory = Paths.get("uploads").toRealPath().normalize()

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request =>
    try {
      val requestedPath = Paths.get("uploads", filename).normalize()
      val canonicalPath = requestedPath.toRealPath()

      if (!canonicalPath.startsWith(baseDirectory)) {
        Forbidden("Access denied.")
      } else {
        val file = new File(canonicalPath.toString)
        if (file.exists() && file.isFile) {
          val fileSource = Source.fromFile(file)
          try {
            Ok(fileSource.mkString).as("application/octet-stream")
          } finally {
            fileSource.close()
          }
        } else {
          NotFound("File not found.")
        }
      }
    } catch {
      case _: Exception => BadRequest("Invalid file path.")
    }
  }
}